// Get all items from the Salesforce query
const items = $input.all();

console.log('Raw items from input:', JSON.stringify(items, null, 2));

// Check if we actually have data
// Salesforce node returns empty array when no results, OR returns items with no records
let hasData = false;
let recordCount = 0;

if (items && items.length > 0) {
  // Check if the items have actual Salesforce data
  // Look for typical Salesforce fields like Id, or your custom fields
  const firstItem = items[0].json;

  // If the first item has an Id field (Salesforce records always have Id)
  // or has your date field, then we have real data
  if (firstItem && (firstItem.Id || firstItem.Date__c)) {
    hasData = true;
    recordCount = items.length;
  }
}

console.log('Has data:', hasData);
console.log('Record count:', recordCount);

// If no data, return a single item with hasData: false
if (!hasData) {
  return [{
    json: {
      hasData: false,
      recordCount: 0,
      message: 'No timesheet records found for the date range'
    }
  }];
}

// If we have data, pass it through with metadata
return items.map(item => ({
  json: {
    hasData: true,
    recordCount: recordCount,
    // Keep ALL the original Salesforce data
    ...item.json
  }
}));

// Get current date
const now = new Date();
const dayOfWeek = now.getDay(); // 0=Sunday, 1=Monday, etc.

// Calculate days to subtract to get to previous Monday
// If today is Sunday (0), go back 6 days
// If today is Monday (1), go back 7 days to previous Monday
// If today is Tuesday (2), go back 8 days, etc.
const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek + 6;

// Calculate previous Monday (start of reporting week)
const previousMonday = new Date(now);
previousMonday.setDate(now.getDate() - daysToSubtract);
previousMonday.setHours(0, 0, 0, 0);

// Calculate previous Sunday (end of reporting week)
const previousSunday = new Date(previousMonday);
previousSunday.setDate(previousMonday.getDate() + 6);
previousSunday.setHours(23, 59, 59, 999);

// Format for Salesforce (YYYY-MM-DD)
function formatDate(date) {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

// Format for display (e.g., "Week of Jan 6-12, 2025")
function formatDisplayDate(date) {
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 
                  'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  return `${months[date.getMonth()]} ${date.getDate()}`;
}

// Return the calculated dates
return {
  startDate: formatDate(previousMonday),
  endDate: formatDate(previousSunday),
  weekLabel: `Week of ${formatDisplayDate(previousMonday)} - ${formatDisplayDate(previousSunday)}, ${previousMonday.getFullYear()}`,
  debug: {
    today: formatDate(now),
    dayOfWeek: dayOfWeek,
    daysSubtracted: daysToSubtract
  }
};

// Get the calculated dates from previous node
const startDate = $node["Calculate Date Range"].json.startDate;
const endDate = $node["Calculate Date Range"].json.endDate;

// CUSTOMIZE THESE NAMES TO MATCH YOUR SALESFORCE OBJECT/FIELDS
const objectName = 'Time_Sheet__c';
const volunteerField = 'Name';
const emailField = 'User_Email__c';
const dateField = 'Date__c';
const hoursField = 'Duration_Hours__c';
const programField = 'Departments__c';
const notesField = 'Summary__c';

// Build the SOQL query dynamically
const query = `SELECT Id, ${volunteerField}, ${emailField}, ${dateField}, ${hoursField}, ${programField}, ${notesField} FROM ${objectName} WHERE ${dateField} >= ${startDate} AND ${dateField} <= ${endDate} ORDER BY ${dateField} ASC, ${emailField} ASC`;

console.log('Generated SOQL Query:', query);

return {
  query: query,
  startDate: startDate,
  endDate: endDate
};

// Get all items from Salesforce query
const records = $input.all().map(item => item.json);

console.log('Processing records:', records.length);

// Initialize data structures
const overall = {
  totalHours: 0,
  uniqueVolunteers: new Set(),
  recordCount: records.length
};

const byProgram = {};
const byVolunteer = {};

// Helper function to extract volunteer name from the Name field
function extractVolunteerName(fullName) {
  if (!fullName) return 'Unknown Volunteer';
  const parts = fullName.split(' - ');
  return parts[0].trim();
}

// Process each timesheet record
records.forEach(record => {
  const volunteerId = record.User_Email__c || 'no-email@unknown.com';
  const volunteerName = extractVolunteerName(record.Name);
  const volunteerEmail = record.User_Email__c || 'No Email';
  const hours = parseFloat(record.Duration_Hours__c || 0);

  // Read Departments__c directly (text/picklist field)
  let program = record.Departments__c || 'No Department';

  const date = record.Date__c;
  const notes = record.Summary__c || '';

  // Overall totals
  overall.totalHours += hours;
  overall.uniqueVolunteers.add(volunteerId);

  // Group by program
  if (!byProgram[program]) {
    byProgram[program] = {
      totalHours: 0,
      volunteers: new Set(),
      entries: []
    };
  }
  byProgram[program].totalHours += hours;
  byProgram[program].volunteers.add(volunteerId);
  byProgram[program].entries.push({
    volunteer: volunteerName,
    email: volunteerEmail,
    hours: hours,
    date: date
  });

  // Group by volunteer (using email as key)
  if (!byVolunteer[volunteerId]) {
    byVolunteer[volunteerId] = {
      name: volunteerName,
      email: volunteerEmail,
      totalHours: 0,
      programs: new Set(),
      entries: []
    };
  }
  byVolunteer[volunteerId].totalHours += hours;
  byVolunteer[volunteerId].programs.add(program);
  byVolunteer[volunteerId].entries.push({
    date: date,
    hours: hours,
    program: program,
    notes: notes
  });
});

// Convert Sets to numbers for final output
overall.uniqueVolunteers = overall.uniqueVolunteers.size;

Object.keys(byProgram).forEach(program => {
  byProgram[program].volunteers = byProgram[program].volunteers.size;
});

// Calculate average hours per volunteer (2 decimal places)
overall.avgHoursPerVolunteer = overall.uniqueVolunteers > 0 
  ? (overall.totalHours / overall.uniqueVolunteers).toFixed(2)
  : "0.00";

// Get all volunteers sorted by hours
const allVolunteers = Object.values(byVolunteer)
  .map(v => ({
    name: v.name,
    email: v.email,
    hours: v.totalHours.toFixed(2),
    programs: Array.from(v.programs).join(', ')
  }))
  .sort((a, b) => parseFloat(b.hours) - parseFloat(a.hours));

// Group volunteers by hour ranges
const volunteersByRange = {
  high: allVolunteers.filter(v => parseFloat(v.hours) >= 15),
  medium_high: allVolunteers.filter(v => parseFloat(v.hours) >= 10 && parseFloat(v.hours) < 15),
  medium: allVolunteers.filter(v => parseFloat(v.hours) >= 5 && parseFloat(v.hours) < 10),
  low: allVolunteers.filter(v => parseFloat(v.hours) >= 2 && parseFloat(v.hours) < 5),
  very_low: allVolunteers.filter(v => parseFloat(v.hours) < 2)
};

// Get week label from earlier node
const weekLabel = $node["Calculate Date Range"].json.weekLabel;

console.log('Aggregation complete. Total hours:', overall.totalHours.toFixed(2));
console.log('Unique volunteers (by email):', overall.uniqueVolunteers);

// Return all aggregated data
return {
  overall,
  byProgram,
  byVolunteer,
  allVolunteers,
  volunteersByRange,
  weekLabel
};

const data = $input.all()[0].json;

// Check for required fields
if (!data.overall || !data.byProgram || !data.allVolunteers) {
  throw new Error('Aggregation failed: Missing required data structures');
}

// Validate total hours makes sense
if (data.overall.totalHours < 0) {
  throw new Error('Invalid data: Negative total hours');
}

if (data.overall.totalHours > 10000) {
  console.warn('Warning: Very high total hours detected:', data.overall.totalHours);
}

// Clean up volunteer names (remove extra spaces, etc.)
data.allVolunteers = data.allVolunteers.map(v => ({
  ...v,
  name: v.name.trim().replace(/\s+/g, ' ')
}));

// Programs/Departments come dynamically from Salesforce Departments__c field
// No need for hardcoded expected programs

return data;

// ========================================
// HELPER FUNCTIONS FOR CHARACTER LIMITS
// ========================================

function truncateText(text, maxLength = 2800, suffix = '\n\n_[Message truncated due to length]_') {
  if (text.length <= maxLength) {
    return text;
  }
  const truncateAt = text.lastIndexOf('\n', maxLength - suffix.length);
  const cutPoint = truncateAt > 0 ? truncateAt : maxLength - suffix.length;
  return text.substring(0, cutPoint) + suffix;
}

function splitIntoChunks(text, maxLength = 2800) {
  if (text.length <= maxLength) {
    return [text];
  }
  const chunks = [];
  let remainingText = text;
  while (remainingText.length > 0) {
    if (remainingText.length <= maxLength) {
      chunks.push(remainingText);
      break;
    }
    let breakPoint = remainingText.lastIndexOf('\n', maxLength);
    if (breakPoint === -1 || breakPoint < maxLength * 0.8) {
      breakPoint = remainingText.lastIndexOf(' ', maxLength);
    }
    if (breakPoint === -1) {
      breakPoint = maxLength;
    }
    chunks.push(remainingText.substring(0, breakPoint));
    remainingText = remainingText.substring(breakPoint).trim();
  }
  return chunks;
}

function buildVolunteerList(volunteersByRange, maxChars = 2800) {
  let text = "*\ud83d\udc65 All Volunteer Hours* (sorted by hours, descending)\n\n";
  let currentLength = text.length;
  let totalVolunteers = 0;
  let shownVolunteers = 0;
  const ranges = [
    { key: 'high', label: '*15+ hours:*', showAll: true },
    { key: 'medium_high', label: '*10-14.9 hours:*', showAll: true },
    { key: 'medium', label: '*5-9.9 hours:*', limit: 15 },
    { key: 'low', label: '*2-4.9 hours:*', limit: 10 },
    { key: 'very_low', label: '*Under 2 hours:*', limit: 5 }
  ];
  ranges.forEach(range => {
    totalVolunteers += (volunteersByRange[range.key] || []).length;
  });
  let truncated = false;
  for (const range of ranges) {
    const volunteers = volunteersByRange[range.key] || [];
    if (volunteers.length === 0) continue;
    const headerText = `${range.label}\n`;
    if (currentLength + headerText.length > maxChars - 200) {
      truncated = true;
      break;
    }
    text += headerText;
    currentLength += headerText.length;
    const showCount = range.showAll ? volunteers.length : Math.min(range.limit || 10, volunteers.length);
    for (let i = 0; i < showCount; i++) {
      const v = volunteers[i];
      const line = `\u2022 ${v.name} - ${v.hours} hrs (${v.programs})\n`;
      if (currentLength + line.length > maxChars - 200) {
        truncated = true;
        break;
      }
      text += line;
      currentLength += line.length;
      shownVolunteers++;
    }
    if (truncated) break;
    if (!range.showAll && volunteers.length > showCount) {
      const moreText = `\u2022 ... [+${volunteers.length - showCount} more volunteers]\n`;
      text += moreText;
      currentLength += moreText.length;
      shownVolunteers += (volunteers.length - showCount);
    }
    text += "\n";
    currentLength += 1;
  }
  return {
    text: text,
    totalVolunteers: totalVolunteers,
    shownVolunteers: shownVolunteers,
    truncated: truncated
  };
}

function buildVolunteerContinuation(volunteersByRange, skipCount) {
  const continuationBlocks = [];
  let currentBlock = "";
  let skipped = 0;
  let currentLength = 0;
  const maxLength = 2800;
  const ranges = [
    { key: 'high', label: '*15+ hours (continued):*' },
    { key: 'medium_high', label: '*10-14.9 hours (continued):*' },
    { key: 'medium', label: '*5-9.9 hours (continued):*' },
    { key: 'low', label: '*2-4.9 hours (continued):*' },
    { key: 'very_low', label: '*Under 2 hours (continued):*' }
  ];
  for (const range of ranges) {
    const volunteers = volunteersByRange[range.key] || [];
    if (volunteers.length === 0) continue;
    let rangeStarted = false;
    for (let i = 0; i < volunteers.length; i++) {
      if (skipped < skipCount) {
        skipped++;
        continue;
      }
      if (!rangeStarted) {
        const headerText = `${range.label}\n`;
        if (currentLength + headerText.length > maxLength - 100) {
          if (currentBlock.length > 0) {
            continuationBlocks.push(currentBlock);
          }
          currentBlock = headerText;
          currentLength = headerText.length;
        } else {
          currentBlock += headerText;
          currentLength += headerText.length;
        }
        rangeStarted = true;
      }
      const v = volunteers[i];
      const line = `\u2022 ${v.name} - ${v.hours} hrs (${v.programs})\n`;
      if (currentLength + line.length > maxLength - 100) {
        continuationBlocks.push(currentBlock);
        currentBlock = line;
        currentLength = line.length;
      } else {
        currentBlock += line;
        currentLength += line.length;
      }
    }
    if (rangeStarted) {
      currentBlock += "\n";
      currentLength += 1;
    }
  }
  if (currentBlock.length > 0) {
    continuationBlocks.push(currentBlock);
  }
  return continuationBlocks;
}

function getCharCount(text) {
  return (text || '').length;
}

// ========================================
// START OF MAIN CODE
// ========================================

const data = $input.all()[0].json;

// Build volunteer list with smart truncation
const volunteerListResult = buildVolunteerList(data.volunteersByRange, 2800);
const volunteerListText = volunteerListResult.text;

console.log('Volunteer list character count:', getCharCount(volunteerListText));
console.log('Shown volunteers:', volunteerListResult.shownVolunteers, '/', volunteerListResult.totalVolunteers);

// Build program summary with truncation
let programText = "*\ud83d\udcc8 By Program*\n" + Object.keys(data.byProgram)
  .filter(program => data.byProgram[program].totalHours > 0)
  .map(program => {
    const p = data.byProgram[program];
    return `\u2022 ${program}: ${p.totalHours.toFixed(2)} hrs (${p.volunteers} volunteers)`;
  })
  .join('\n');

programText = truncateText(programText, 1000);
console.log('Program text character count:', getCharCount(programText));

// Build Slack message blocks
const blocks = [
  {
    "type": "header",
    "text": {
      "type": "plain_text",
      "text": "\ud83c\udf1f Weekly Volunteer Impact Report",
      "emoji": true
    }
  },
  {
    "type": "context",
    "elements": [
      {
        "type": "mrkdwn",
        "text": truncateText(data.weekLabel, 75)
      }
    ]
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*\ud83d\udcca Overview*\n\u2022 Total Hours: *${data.overall.totalHours.toFixed(2)}* hours\n\u2022 Active Volunteers: *${data.overall.uniqueVolunteers}* people\n\u2022 Average Hours/Volunteer: *${data.overall.avgHoursPerVolunteer}* hours\n\u2022 Timesheet Entries: ${data.overall.recordCount}`
    }
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": volunteerListText
    }
  }
];

// Add continuation blocks if volunteers were truncated
if (volunteerListResult.truncated) {
  console.log('Volunteers truncated, building continuation blocks...');
  const continuationBlocks = buildVolunteerContinuation(
    data.volunteersByRange, 
    volunteerListResult.shownVolunteers
  );
  console.log('Created', continuationBlocks.length, 'continuation blocks');
  continuationBlocks.forEach((blockText, index) => {
    blocks.push({
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": blockText
      }
    });
    console.log(`Continuation block ${index + 1} character count:`, getCharCount(blockText));
  });
}

// Add program summary
blocks.push({
  "type": "section",
  "text": {
    "type": "mrkdwn",
    "text": truncateText(programText, 2800)
  }
});

// Add divider before footer
blocks.push({
  "type": "divider"
});

// Add footer
blocks.push({
  "type": "section",
  "text": {
    "type": "mrkdwn",
    "text": `_\ud83e\uddea SANDBOX TEST - Report generated from test data_\n_Generated: ${new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })}_`
  }
});

// Final safety check
console.log('Total blocks before limit check:', blocks.length);
if (blocks.length > 50) {
  console.warn('WARNING: Exceeding 50 block limit! Truncating...');
  blocks.splice(49);
  blocks.push({
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": "\u26a0\ufe0f *Report truncated* - Message exceeded Slack's 50 block limit."
    }
  });
}

console.log('Final block count:', blocks.length);

blocks.forEach((block, i) => {
  if (block.type === 'section' && block.text) {
    const charCount = getCharCount(block.text.text);
    console.log(`Block ${i} (${block.type}): ${charCount} chars`);
    if (charCount > 3000) {
      console.error(`ERROR: Block ${i} exceeds 3000 character limit!`);
    }
  }
  if (block.type === 'context' && block.elements) {
    block.elements.forEach((el, j) => {
      const charCount = getCharCount(el.text);
      console.log(`Block ${i} context element ${j}: ${charCount} chars`);
      if (charCount > 75) {
        console.error(`ERROR: Context element ${j} in block ${i} exceeds 75 character limit!`);
      }
    });
  }
});

// Return the formatted blocks
return [{
  json: {
    blocksJson: JSON.stringify({ blocks: blocks }),
    blocks: blocks,
    text: "Weekly Volunteer Impact Report"
  }
}];

// Get the week label from the Calculate Date Range node
const weekLabel = $node["Calculate Date Range"].json.weekLabel;
const startDate = $node["Calculate Date Range"].json.startDate;
const endDate = $node["Calculate Date Range"].json.endDate;

// Create a formatted Slack message using Block Kit
const blocks = [
  {
    "type": "header",
    "text": {
      "type": "plain_text",
      "text": "\u26a0\ufe0f No Volunteer Data Found",
      "emoji": true
    }
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `*${weekLabel}*\n\nNo volunteer timesheet entries were found for the reporting period.`
    }
  },
  {
    "type": "section",
    "fields": [
      {
        "type": "mrkdwn",
        "text": `*Start Date:*\n${startDate}`
      },
      {
        "type": "mrkdwn",
        "text": `*End Date:*\n${endDate}`
      }
    ]
  },
  {
    "type": "divider"
  },
  {
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": "*Possible reasons:*\n\u2022 No volunteers logged hours this week\n\u2022 Timesheets haven't been submitted yet\n\u2022 Data sync issue with Salesforce\n\u2022 Date range calculation error"
    }
  },
  {
    "type": "context",
    "elements": [
      {
        "type": "mrkdwn",
        "text": `\ud83e\udd16 Automated report \u2022 ${new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })}`
      }
    ]
  }
];

return [{
  json: {
    blocksJson: JSON.stringify({ blocks: blocks }),
    blocks: blocks,
    text: "\u26a0\ufe0f No Volunteer Data Found",
    weekLabel: weekLabel
  }
}];
